 SELECT schemesid,
    schemename,
    coverage,
    maxpayable,
    recovery
   FROM public.schemes
  WHERE (isactive = true)
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.vwm_schemes OWNER TO postgres;

--
-- TOC entry 262 (class 1259 OID 67321)
-- Name: vwm_services; Type: MATERIALIZED VIEW; Schema: public; Owner: postgres
--

CREATE MATERIALIZED VIEW public.vwm_services AS
 SELECT ss.schemeservicesid,
    ss.servicesid,
    ss.price,
    ss.allowedtiers AS tiers,
    ss.gdrg,
    ss.narration,
    s.service,
    s.servicegroup
   FROM (public.schemeservices ss
     JOIN public.services s ON ((s.servicesid = ss.servicesid)))
  WHERE ss.isactive
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.vwm_services OWNER TO postgres;

